const brief = $json.body;
const requiredFields = ['position', 'department', 'responsibilities', 'requirements']; // Пример обязательных полей
let isValid = requiredFields.every(field => brief[field] && brief[field].trim() !== '');
$json.isValid = isValid;
return $json;

const data = $json;
const fileContent = `Вакансия: ${data.position}\nОтдел: ${data.department}\n\nОбязанности:\n${data.responsibilities}\n\nТребования:\n${data.requirements}`;

const binaryData = Buffer.from(fileContent, 'utf8');

return [
  {
    json: data,
    binary: {
      data: binaryData.toString('base64'),
      fileName: `Вакансия - ${data.position}.txt`,
      mimeType: 'text/plain'
    }
  }
];

const text = $json.content;
const cleanedText = text.replace(/```json\n|\n```/g, '');
const analysis = JSON.parse(cleanedText);
return { ...$item.json, analysis };

